package com.careeros.provider.infrastructure.generic;

import com.careeros.company.domain.Company;import com.careeros.job.application.JobPostingCommand;import com.careeros.job.infrastructure.ingestion.support.*;import com.careeros.provider.application.JobProvider;import com.careeros.provider.domain.ProviderType;import com.fasterxml.jackson.databind.ObjectMapper;import org.jsoup.Jsoup;import org.springframework.stereotype.Component;import org.springframework.web.client.RestClient;import java.time.LocalDate;import java.util.*;
@Component public class GenericRssProvider implements JobProvider{private final RestClient client;private final ObjectMapper mapper;public GenericRssProvider(RestClient.Builder b,ObjectMapper m){client=b.build();mapper=m;}public ProviderType providerType(){return ProviderType.GENERIC_RSS;}public List<JobPostingCommand>fetchJobs(Company c){var cfg=new ProviderConfiguration(mapper,c.getProviderConfiguration());String xml=GenericProviderSupport.retry(3,()->client.get().uri(cfg.required("feedUrl")).retrieve().body(String.class));var doc=Jsoup.parse(xml,"",org.jsoup.parser.Parser.xmlParser());List<JobPostingCommand>out=new ArrayList<>();for(var e:doc.select("item, entry")){String title=GenericProviderSupport.value(e,"title"),loc=GenericProviderSupport.value(e,Optional.ofNullable(cfg.text("locationSelector")).orElse("location"));var link=e.selectFirst("link");String apply=link==null?null:Optional.ofNullable(link.attr("href")).filter(x->!x.isBlank()).orElse(link.text());String id=Optional.ofNullable(GenericProviderSupport.value(e,"guid")).orElse(GenericProviderSupport.value(e,"id"));String desc=Optional.ofNullable(GenericProviderSupport.value(e,"description")).orElse(GenericProviderSupport.value(e,"summary"));if(title==null||apply==null)continue;out.add(new JobPostingCommand(id==null?Integer.toHexString(apply.hashCode()):id,c.getId(),title,loc,EmploymentTypeParser.fromKeyword(title),RemoteHeuristic.looksRemote(title,loc),null,null,null,desc,LocalDate.now(),apply));}return out;}}
